namespace sv_f5abbd3b431d4e25b7041dbbf6cfcf0e.Services;

public enum Theme
{
    Light,
    Dark,
    System
}

/// <summary>
/// Circuit-scoped service that holds theme state and notifies subscribers on change.
/// Registered as Scoped so each SignalR circuit (user) gets its own instance.
/// </summary>
public sealed class ThemeService
{
    private Theme _theme = Theme.System;
    private string _accentColor = "#0d6efd";

    public Theme Theme => _theme;
    public string AccentColor => _accentColor;

    public event Action? OnChange;

    public void SetTheme(Theme theme)
    {
        if (_theme == theme) return;
        _theme = theme;
        OnChange?.Invoke();
    }

    public void SetAccentColor(string color)
    {
        if (_accentColor == color) return;
        _accentColor = color;
        OnChange?.Invoke();
    }
}

@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<span class="badge" style="background-color: @ThemeService.AccentColor;">
    @ThemeService.Theme
</span>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += HandleThemeChanged;
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnChange -= HandleThemeChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="mb-3">
    <label class="form-label fw-bold">Theme</label>
    <div class="btn-group d-block" role="group">
        @foreach (var t in Enum.GetValues<Theme>())
        {
            var isActive = ThemeService.Theme == t;
            <button class="btn @(isActive ? "btn-primary" : "btn-outline-primary")"
                    @onclick="() => ThemeService.SetTheme(t)">
                @t
            </button>
        }
    </div>
</div>

<div class="mb-3">
    <label class="form-label fw-bold">Accent Color</label>
    <input type="color"
           class="form-control form-control-color"
           value="@ThemeService.AccentColor"
           @onchange="OnColorChanged" />
    <span class="form-text">Current: @ThemeService.AccentColor</span>
</div>

<div class="alert mt-4" style="border-left: 4px solid @ThemeService.AccentColor;">
    <strong>Preview:</strong> Theme is <em>@ThemeService.Theme</em> with accent
    <span style="color: @ThemeService.AccentColor;">@ThemeService.AccentColor</span>.
    Check the header indicator — it updates in real time.
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += HandleThemeChanged;
    }

    private void OnColorChanged(ChangeEventArgs e)
    {
        ThemeService.SetAccentColor(e.Value?.ToString() ?? "#0d6efd");
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnChange -= HandleThemeChanged;
    }
}

