@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="mb-3">
    <label class="form-label fw-bold">Theme</label>
    <div class="btn-group d-block" role="group">
        @foreach (var t in Enum.GetValues<Theme>())
        {
            var isActive = ThemeService.Theme == t;
            <button class="btn @(isActive ? "btn-primary" : "btn-outline-primary")"
                    @onclick="() => ThemeService.SetTheme(t)">
                @t
            </button>
        }
    </div>
</div>

<div class="mb-3">
    <label class="form-label fw-bold">Accent Color</label>
    <input type="color"
           class="form-control form-control-color"
           value="@ThemeService.AccentColor"
           @onchange="OnColorChanged" />
    <span class="form-text">Current: @ThemeService.AccentColor</span>
</div>

<div class="alert mt-4" style="border-left: 4px solid @ThemeService.AccentColor;">
    <strong>Preview:</strong> Theme is <em>@ThemeService.Theme</em> with accent
    <span style="color: @ThemeService.AccentColor;">@ThemeService.AccentColor</span>.
    Check the header indicator — it updates in real time.
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += HandleThemeChanged;
    }

    private void OnColorChanged(ChangeEventArgs e)
    {
        ThemeService.SetAccentColor(e.Value?.ToString() ?? "#0d6efd");
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnChange -= HandleThemeChanged;
    }
}

